class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        MOD = 10**9 + 7
        n = zero + one
        dp = [[[0]*(limit+2) for _ in range(one+1)] for _ in range(n+1)]
        dp[0][0][0] = 1
        for i in range(1, n+1):
            for j in range(min(i, one)+1):
                for k in range(limit+1):
                    if j > 0:
                        dp[i][j][1] = (dp[i][j][1] + dp[i-1][j-1][k+1]) % MOD
                    if k > 0 and zero > i - j:
                        dp[i][j][k+1] = (dp[i][j][k+1] + dp[i-1][j][k-1]) % MOD
        ans = 0
        for k in range(limit+1):
            ans = (ans + dp[n][one][k]) % MOD
        return ans
```
